const items = $input.all();

const output = items.map(item => {

  const data = item.json; 
  const linkedinUrl = data.sender_identifier 
    ? `https://www.linkedin.com/in/${data.sender_identifier}`
    : null;

  return {
    json: {
      ...data,
      linkedin_url: linkedinUrl
    }
  };
});

return output;

