// Get the webhook data from n8n input
const inputData = $input.all()[0].json;

console.log('Full Input:', JSON.stringify(inputData, null, 2));

// Handle different possible structures
let webhookData;

// Check if it's already the webhook object or wrapped in an array
if (Array.isArray(inputData)) {
  webhookData = inputData[0];
} else if (inputData.body) {
  webhookData = inputData;
} else {
  // Maybe the previous node already extracted body
  webhookData = { body: inputData };
}

console.log('Webhook Data:', JSON.stringify(webhookData, null, 2));

// Check if we have the event data
if (!webhookData.body || !webhookData.body.event) {
  throw new Error('Cannot find event data in webhook. Structure: ' + JSON.stringify(Object.keys(webhookData)));
}

// Extract the event data
const event = webhookData.body.event;
const target = event.target;
const account = event.account;
const campaign = event.campaign;
const workspace = webhookData.body.workspace;

// Normalize the data
const normalizedData = {
  // Basic contact info
  first_name: target.first_name.trim(),
  last_name: target.last_name.trim(),
  email: target.email,

  // LinkedIn info
  linkedin_url: `https://www.linkedin.com/in/${target.public_identifier}`,
  linkedin_id: target.id,
  linkedin_urn: target.urn,

  // Message details
  message: event.message,
  reply_timestamp: event.timestamp,

  // Campaign info
  campaign_id: campaign.id,
  campaign_name: campaign.name,
  campaign_type: campaign.type,

  // Flow info
  flow_id: event.flow_id,
  flow_type: event.flow_type,

  // Event metadata
  event_type: webhookData.body.event_type,
  event_id: webhookData.body.id,
  previous_state: event.prev_state,
  current_state: event.state,

  // Account (sender) info
  sender_first_name: account.first_name.trim(),
  sender_last_name: account.last_name.trim(),
  sender_email: account.email,
  sender_linkedin_url: `https://www.linkedin.com/in/${account.public_identifier}`,

  // Workspace info
  workspace_id: workspace.id,
  workspace_name: workspace.name,

  // Profile pictures
  profile_picture: target.picture_url,
  sender_picture: account.picture_url
};

return { json: normalizedData };
